-- Normalize seeded camera stream credentials and replace bcrypt placeholders with AES-GCM ciphertext.

UPDATE camera_streams
SET source_url = regexp_replace(source_url, '^([a-z]+://)[^/@]+@', '\1')
WHERE source_url ~ '^[a-z]+://[^/@]+@';

UPDATE camera_streams
SET playback_url = CASE
        WHEN source_protocol = 'HTTP' THEN regexp_replace(source_url, '^[a-z]+://', 'http://') || '/pass.flv'
        WHEN source_protocol = 'HTTPS' THEN regexp_replace(source_url, '^[a-z]+://', 'https://') || '/pass.flv'
        ELSE NULL
    END,
    playback_protocol = CASE
        WHEN source_protocol = 'HTTP' THEN 'HTTP'::protocol_enum
        WHEN source_protocol = 'HTTPS' THEN 'HTTPS'::protocol_enum
        ELSE NULL
    END;

