UPDATE camera_streams cs
SET stream_password_ciphertext = sd.stream_password_ciphertext,
    stream_password_iv = sd.stream_password_iv,
    stream_password_key_version = 'v1',
    credential_updated_at = COALESCE(cs.updated_at, cs.created_at, now())
FROM seed_data sd
WHERE cs.stream_id = sd.stream_id;

